#include <iostream>
using namespace std;

int russianPeasant(int a, int b) {
    int result = 0;

    // While second number is greater than 0
    while(b > 0) {
        // If second number is odd
        // add the first number to result
        if(b & 1) {  // Same as b % 2 == 1
            result = result + a;
        }

        // Double first number
        a = a << 1;  // Same as a = a * 2

        // Halve second number
        b = b >> 1;  // Same as b = b / 2
    }

    return result;
}

int main() {
    int t;
    cin >> t;

    while(t--) {
        int a, b;
        cin >> a >> b;
        cout << russianPeasant(a, b) << endl;
    }

    return 0;
}
